frappe.web_form.after_load = () => {
    frappe.web_form.set_df_property('extra_details', 'hidden', 1);

    setTimeout(() => {
        let parent = document.querySelector('.web-form-body') || 
                     document.querySelector('.form-body') || 
                     document.querySelector('form');

        if (!parent || document.getElementById('manual-custom-questions')) return;

        let custom_section = document.createElement('div');
        custom_section.id = "manual-custom-questions";
        custom_section.className = "web-form-container";

        custom_section.innerHTML = `
            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <div class="clearfix">
                        <label class="control-label">Click here for updates - <a href="https://chat.whatsapp.com/xyz" style="color: #28a745; font-weight: bold;" target="_blank">WhatsApp Group</a></label>
                    </div>
                    <div class="control-input-wrapper">
                        <div class="checkbox">
                            <label>
                                <input type="checkbox" id="custom_whatsapp" style="margin-top: 2px;">
                                <span class="label-area" style="margin-left: 8px;">I have joined the above WhatsApp group</span>
                            </label>
                        </div>
                    </div>
                </div>
            </div>

            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <div class="clearfix">
                        <label class="control-label">Number of kits you'd like to distribute</label>
                    </div>
                    <div class="control-input-wrapper">
                        <input type="number" id="custom_kits" class="form-control" min="1" value="1">
                    </div>
                </div>
            </div>

            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <div class="clearfix">
                        <label class="control-label">Where would you like the kits to be distributed?</label>
                    </div>
                    <div class="control-input-wrapper">
                        <select id="custom_location" class="form-control" onchange="document.getElementById('address_wrapper').style.display = this.value === 'Residential' ? 'block' : 'none'">
                            <option value="MSFT Campus IDC">MSFT Campus IDC</option>
                            <option value="Residential">To my Residential Address</option>
                        </select>
                    </div>
                </div>
            </div>

            <div id="address_wrapper" class="frappe-control" style="margin-bottom: var(--margin-md); display: none;">
                <div class="form-group">
                    <div class="clearfix">
                        <label class="control-label">Residential Address <span class="text-danger">*</span></label>
                    </div>
                    <div class="control-input-wrapper">
                        <textarea id="custom_address" class="form-control" rows="3" style="height: auto;" placeholder="Enter your full home address..."></textarea>
                    </div>
                </div>
            </div>

            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <div class="clearfix">
                        <label class="control-label">Would you like to help us organise this event?</label>
                    </div>
                    <div class="control-input-wrapper">
                        <select id="custom_committee" class="form-control">
                            <option value="">Perhaps, next time</option>
                            <option value="Option 1">I want to inspire 5+ people to participate so that more underprivileged can be benefited</option>
                            <option value="Option 2">I wish to be a POC, helping in event coordination, and post-event follow-up, including getting volunteering hours tracked</option>
                            <option value="Option 3">I wish to do both of the above</option>
                        </select>
                    </div>
                </div>
            </div>
        `;

        parent.append(custom_section);
    }, 200);
};

frappe.web_form.validate = () => {
    // Helper to get selected text instead of the value (ID)
    const getSelectedText = (id) => {
        const e = document.getElementById(id);
        return e ? e.options[e.selectedIndex].text : "";
    };

    const joined = document.getElementById('custom_whatsapp')?.checked || false;
    const kits = document.getElementById('custom_kits')?.value || 0;

    // Check the raw value for the IF logic, but grab the TEXT for saving
    const location_id = document.getElementById('custom_location')?.value;
    const location_text = getSelectedText('custom_location');

    // Capture the content from the textarea
    const address_content = document.getElementById('custom_address')?.value || "";

    const committee_text = getSelectedText('custom_committee');

    // 1. Mandatory Logic
    if (location_id === "Residential" && !address_content.trim()) {
        frappe.msgprint(__('Please provide your residential address for kit distribution.'));
        return false;
    }

    // 2. Map the actual Address content to the DocType field
    frappe.web_form.doc.temp_address = (location_id === "Residential") ? address_content : "";

    // 3. Map everything to Child Table using the pretty text
    let details = [];
    details.push({ "question": "Joined WhatsApp Group", "answer": joined ? "Yes" : "No" });
    details.push({ "question": "Kits to Distribute", "answer": kits });
    details.push({ "question": "Distribution Location", "answer": location_text });

    if (committee_text && committee_text !== "Perhaps, next time") {
        details.push({ "question": "Organizing Committee Role", "answer": committee_text });
    }

    frappe.web_form.doc.extra_details = details;

    return true;
};
